import clearSearchs from "./clearSearchs";
import resetSelectedProducts from "./resetSelectedProducts";

export default function handleConfirmationModal() {
  const confirmationModal = document.querySelector(".unavailable-confirmation");
  const categoriesWrapper = document.querySelector(
    ".unavailable__table-wrapper--categories"
  );
  const productsWrapper = document.querySelector(
    ".unavailable__table-wrapper--products"
  );
  const cancelButton = confirmationModal.querySelector(
    ".unavailable-confirmation__button--cancel"
  );
  const confirmButton = confirmationModal.querySelector(
    ".unavailable-confirmation__button--confirm"
  );
  const closeButton = confirmationModal.querySelector(
    ".unavailable-confirmation__close"
  );

  if (!confirmationModal || !cancelButton || !confirmButton || !closeButton) {
    return;
  }

  const hideModal = () => {
    confirmationModal.classList.remove("unavailable-confirmation--active");
  };

  const switchToCategories = () => {
    categoriesWrapper.classList.remove("unavailable__table-wrapper--hidden");
    productsWrapper.classList.add("unavailable__table-wrapper--hidden");
    clearSearchs();
    resetSelectedProducts();
  };

  const handleCancel = () => {
    hideModal();
    switchToCategories();
  };

  const handleConfirm = async () => {
    const loadingOverlay = document.createElement("div");
    loadingOverlay.className = "unavailable__loading-overlay";
    loadingOverlay.innerHTML = `
      <div class="unavailable__loader">
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200">
          <radialGradient id="loader-gradient-save" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
            <stop offset="0" stop-color="#0085BA"/>
            <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
            <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
            <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
            <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
          </radialGradient>
          <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-save)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
            <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
          </circle>
        </svg>
      </div>
    `;
    document.body.appendChild(loadingOverlay);

    try {
      const productsSaveButton = document.querySelector(
        ".unavailable__table-actions-products-save-btn"
      );

      if (!productsSaveButton) {
        return;
      }

      hideModal();

      productsSaveButton.disabled = false;
      productsSaveButton.click();
    } catch (error) {
      console.error("Błąd podczas zapisywania produktów:", error);
    } finally {
      document.body.removeChild(loadingOverlay);
    }
  };

  cancelButton.addEventListener("click", handleCancel);
  confirmButton.addEventListener("click", handleConfirm);
  closeButton.addEventListener("click", hideModal);

  confirmationModal.addEventListener("click", (e) => {
    if (e.target === confirmationModal) {
      hideModal();
    }
  });
}
