import loadUnavailableCategories from "./loadUnavailableCategories";

export default function loadSearchs() {
  const setupSearch = () => {
    const categoriesSearch = document.querySelector(
      ".unavailable__search-main"
    );

    if (categoriesSearch && !categoriesSearch.dataset.listenerAdded) {
      let timeout = null;

      categoriesSearch.addEventListener("input", (e) => {
        if (timeout) {
          clearTimeout(timeout);
        }

        timeout = setTimeout(async () => {
          try {
            await loadUnavailableCategories(1);
          } catch (error) {
            if (error.message !== "Request cancelled") {
              console.error("Search failed:", error);
            }
          }
        }, 300);
      });

      categoriesSearch.addEventListener("keydown", (e) => {
        if (e.key === "Escape") {
          e.target.value = "";
          loadUnavailableCategories(1);
        }
      });

      categoriesSearch.dataset.listenerAdded = "true";
    }
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", setupSearch);
  } else {
    setupSearch();
  }

  setTimeout(setupSearch, 500);
}
